var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"GAP-13호 곧 목표 고도에 진입합니다!","JPN":"GAP-13号、もうすぐ目標高度に進入します！","ENG":"GAP-13 will soon reach its target altitude!","TWN":"GAP-13號即將到達目標高度！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지휘부다! 앨리스 전대장, 들리나?","JPN":"司令部だ！　アリス戦隊長、聞こえるか？","ENG":"This is Headquarters! Commander Alice, do you copy?","TWN":"這裡是指揮部！艾莉絲戰隊長，你能聽到我說話嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금 상황은 어떻지?","JPN":"今の状況はどうだ？","ENG":"How are things looking on your side?","TWN":"你現在感覺如何？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"우주복이 답답한 것 빼고 괜찮습니다.","JPN":"宇宙服のせいで息苦しいですが、特に問題はありません。","ENG":"Besides the stuffy spacesuit, I'm all good.","TWN":"除了太空裝有點悶之外，其他都還好。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다행이군.","JPN":"そうか。","ENG":"Good.","TWN":"那就好。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"원인은 알 수 없지만, 현재 정보 오염된 전략위성 외에는 전부 연결이 끊긴 상태야.","JPN":"原因は不明だが、現在情報汚染された戦略衛星を除いたすべて通信が途絶えている状況だ。","ENG":"We haven't figured out the cause yet, but all the other strategic satellites except the data-corrupted one are offline.","TWN":"目前原因尚且不明，但除了受到資訊污染的戰略衛星外，其他衛星均與我們斷開連接。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"혹시 육안으로 지금 우주의 상태를 확인할 수 있겠나?","JPN":"裸眼で今の宇宙の状態を確認できるか？","ENG":"Can you see the current state of outer space with your own eyes right now?","TWN":"你是否能夠用肉眼檢查到目前太空的狀態？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 전대장? 듣고 있나?","JPN":"アリス戦隊長？　聞いているのか？","ENG":"Commander Alice? Do you hear me?","TWN":"艾莉絲戰隊長？你在聽嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐야, 저게……?","JPN":"なんだ、あれ……？","ENG":"What is that...?","TWN":"嗯，那是……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"새잖아……?","JPN":"鳥じゃないか……？","ENG":"It looks like a bird...?","TWN":"是鳥吧……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"새? 무슨 말을 하는 거지?","JPN":"鳥？　何を言っている？","ENG":"A bird? What are you talking about?","TWN":"鳥？你說什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금 자네 뭘 본 건가?","JPN":"君、今何が見えているんだ？","ENG":"Can you describe what you are seeing?","TWN":"你剛才看到了什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……전대장님.","JPN":"……戦隊長。","ENG":"...Commander.","TWN":"……戰隊長。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"지금까지 저희가 적기라고 생각했던 건 정보오염된 전략위성 따위가 아니었습니다.","JPN":"今までアタシたちが敵機だと思ってきたのは、情報汚染された戦略衛星なんかじゃなかったんです。","ENG":"What we thought was the enemy wasn't a data-corrupted strategic satellite.","TWN":"我想那個到目前為止被我們認為是敵機的東西，不是那顆被資訊污染的戰略衛星。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"정체는 모르겠지만…… 청백광을 띈 함선이 우주를 떠돌고 있습니다.","JPN":"正体はわからないですけど……青白い光を纏った艦船が宇宙を彷徨っています。","ENG":"I don't know what it is, but... it looks like a glowing blue-white ship drifting in space.","TWN":"我不知道該怎麼形容……但那好像是，泛著青白色光芒的艦船在太空中徘徊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"청백광의 함선……?","JPN":"青白い光の艦船……？","ENG":"A pale bluish light ship...?","TWN":"青白色光芒的艦船……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"외부 모니터로 지휘부에 전송해드리겠습니다.","JPN":"外部モニターで司令部まで伝送します。","ENG":"I'm transmitting it through the external camera to the Headquarters.","TWN":"我會透過外部監視鏡頭傳輸給指揮部。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저건 대체……?","JPN":"あれはいったい……？","ENG":"What is that...?","TWN":"那個到底是……？"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"아무래도 저 녀석이 이번 사태의 원흉인 게 틀림없습니다.","JPN":"どうやらあいつが今回の事態の元凶のようです。","ENG":"I think that is the culprit of this situation.","TWN":"毫無疑問，那個傢伙就是造成目前情況的罪魁禍首。"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"저 녀석을 제거하지 않으면, 아무것도 바뀌지 않을 것 같은 직감이 듭니다.","JPN":"あいつを取り除かないかぎり、事態は変わらない気がします。","ENG":"My instinct tells me that if I don't eliminate it, nothing will change.","TWN":"我有預感，如果我們不摧毀它，一切都不會改變。"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"우선, 복귀해 앨리스 전대장!","JPN":"まずは、復帰しろ。アリス戦隊長！","ENG":"Firstly, return to base, Commander Alice!","TWN":"請先返航吧，艾莉絲戰隊長！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저것의 정체가 무엇인지도 모르는데, 자네 혼자 저걸 요격하는 건 너무 위험해!","JPN":"あれの正体もわからないのに、君一人で迎撃することはあまりにも危険だ！","ENG":"We don't know what it is. It's dangerous for you to attempt shooting it down on your own!","TWN":"我們連它是什麼都不知道，單獨攔截它太危險了！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……아니요. 이제 남은 시간이 별로 없습니다.","JPN":"……いいえ。もうあまり時間がありません。","ENG":"...No. We don't have enough time.","TWN":"……不。現在剩下的時間不多了。"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"제가 망설일수록, 필하모닉 홀에 있는 동료들은 더 위험에 빠질 겁니다.","JPN":"アタシが迷えば、フィルハーモニーホールにいる仲間たちは更なる危険に陥るはずです。","ENG":"The more I hesitate, the more danger my comrades will be in Philharmonic Hall.","TWN":"我猶豫得越久，身處管弦樂廳的同伴就越多一分危險。"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스, 자네……!!","JPN":"アリス、君……！！","ENG":"Alice...!!","TWN":"艾莉絲隊長……！！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"정체불명의 적기로부터 열원 반응!","JPN":"正体不明の敵機から熱源反応！","ENG":"Detecting heat signals from the unidentified hostile!","TWN":"檢測到不明敵機的熱源反應！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L48_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이건……. 관리국 전략위성의 능동 방어 시스템……?","JPN":"これは……管理局戦略衛星の能動防御システム……？","ENG":"That's... the Administration strategic satellite's active defense system...?","TWN":"這是……管理局戰略衛星的主動防禦系統……？"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"아무래도 저 함선은 전략위성과 도킹하여, 관리국 기술을 자기 것으로 만드는 모양입니다!","JPN":"どうやらあの艦船は戦略衛星にドッキングし、管理局の技術を自分のものにしているようです！","ENG":"It seems that the ship has docked to the satellite and using the Administration's technology as its own!","TWN":"看來那艘艦船是在與戰略衛星對接，盜取管理局的技術據為己有！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"GAP-13호에는 적의 공격에 대처할 화기가 없습니다!","JPN":"GAP-13号には敵の攻撃に対処する火器が備わっていません！","ENG":"GAP-13 has no firepower to deal with the enemy!","TWN":"GAP-13號沒有配備可以對付敵人的武裝！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"결단하셔야 합니다! 전대장님!","JPN":"決断を！　戦隊長！","ENG":"You must make a decision, Commander!","TWN":"別再猶豫了！戰隊長！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나도 알고 있다고!!!","JPN":"アタシもわかってるよ！！","ENG":"I know that!!!","TWN":"我也知道！！！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"메이즈 전대장님! 제 능력으로 저 함선에 침투하겠습니다!","JPN":"メイズ戦隊長！　アタシの能力であの艦船に浸透します！","ENG":"Maze Commander! I'm going to infiltrate the ship with my ability!","TWN":"梅茲戰隊長！我會用我的能力潛入艦船！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"동력원을 끊으면 다시 통신하겠습니다!","JPN":"動力源を切ったら、また連絡します！","ENG":"I'll radio in again after cutting its power!","TWN":"切斷它的動力源後，我再聯繫你！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스……!!","JPN":"アリス……！！","ENG":"Alice...!!!","TWN":"艾莉絲……！！"},"stage":{"bg":"YAKSHA_03","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"GAP-13호. 격추되었습니다.","JPN":"GAP-13号、撃墜されました。","ENG":"GAP-13 has been shot down.","TWN":"GAP-13號被擊落了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……스스로가 한심해서 견딜 수가 없군.","JPN":"……自分が情けなくてたまらない。","ENG":"...I can't stand myself for acting so pathetically.","TWN":"我……為自己的無能感到羞愧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"우리가 할 수 있는 건, 그저 이렇게 지켜보고, 기다리는 것뿐인가?","JPN":"私たちにできるのは、ただこうして待っていることだけなのか？","ENG":"What are our options? Is just watching and waiting all we can do?","TWN":"難道我們能做的，就只有袖手旁觀和等待嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 브레이드우드.","JPN":"アリス・ブレイドウッド。","ENG":"Alice Braidwood.","TWN":"艾莉絲·布雷德伍德。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"필하모닉 홀에 있는 자네 전대원들은 우리가 반드시 구해내겠네.","JPN":"フィルハーモニーホールにいる君の戦隊員は私たちが必ず助ける。","ENG":"I promise to save your division members trapped in Philharmonic Hall.","TWN":"我們一定會救出你戰隊員，我向你保證。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 요격에 성공하길 빌겠네.","JPN":"だから、今は迎撃の成功を祈ろう。","ENG":"So, I pray that you succeed.","TWN":"所以，祝你攔截成功。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};